@kotlin.contracts.ExperimentalContracts
@kotlin.ExperimentalUnsignedTypes
internal class MusicFontSymbolLookup
{
    companion object{
        @kotlin.jvm.JvmStatic
        private var _allMusicFontSymbols: com.omnifret.gplayer.collections.List<com.omnifret.gplayer.model.MusicFontSymbol> = com.omnifret.gplayer.collections.List<com.omnifret.gplayer.model.MusicFontSymbol>(
        )
        
        
        @kotlin.jvm.JvmStatic
        private var _blackNoteHeadGlyphs: com.omnifret.gplayer.core.ecmaScript.Set<com.omnifret.gplayer.model.MusicFontSymbol> = com.omnifret.gplayer.core.ecmaScript.Set<com.omnifret.gplayer.model.MusicFontSymbol>()
        
        @kotlin.jvm.JvmStatic
        private fun _initialize(): Unit{
            var all: com.omnifret.gplayer.collections.List<com.omnifret.gplayer.model.MusicFontSymbol> = com.omnifret.gplayer.model.MusicFontSymbolLookup._allMusicFontSymbols
            if (all.length == 0.0)
            {
                for (v in com.omnifret.gplayer.core.ecmaScript.Object.values(com.omnifret.gplayer.model.MusicFontSymbol::class).filter<Any>(fun(k: Any): Boolean{
                    return com.omnifret.gplayer.core.TypeHelper.typeOf(k) == "number"
                }
                ))
                {
                    var symbol: com.omnifret.gplayer.model.MusicFontSymbol = com.omnifret.gplayer.model.MusicFontSymbol.fromValue(v.toDouble())
                    all.push(symbol)
                    var name: String = symbol.toString().lowercase()
                    if (name.endsWith("black"))
                    {
                        com.omnifret.gplayer.model.MusicFontSymbolLookup._blackNoteHeadGlyphs.add(symbol)
                    }
                }
            }
        }
        
        /**
         * Gets a list of all music font symbols used in com.omnifret.gplayer.
         */
        @kotlin.jvm.JvmStatic
        public fun getAllMusicFontSymbols(): com.omnifret.gplayer.collections.List<com.omnifret.gplayer.model.MusicFontSymbol>{
            com.omnifret.gplayer.model.MusicFontSymbolLookup._initialize()
            return com.omnifret.gplayer.model.MusicFontSymbolLookup._allMusicFontSymbols
        }
        
        /**
         */
        @kotlin.jvm.JvmStatic
        public fun isBlackNoteHead(glph: com.omnifret.gplayer.model.MusicFontSymbol): Boolean{
            com.omnifret.gplayer.model.MusicFontSymbolLookup._initialize()
            return com.omnifret.gplayer.model.MusicFontSymbolLookup._blackNoteHeadGlyphs.has(glph)
        }
        
    }
    public constructor()
}

